package ir.tahamohamadi.portfolio.project; import ir.tahamohamadi.common.domain.LanguageCode; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*; public interface PortfolioProjectTranslationRepository extends JpaRepository<PortfolioProjectTranslation,UUID>{ @Query("select t from PortfolioProjectTranslation t join t.project p where t.languageCode=:language and t.deletedAt is null and p.deletedAt is null and p.status='PUBLISHED' order by p.sortOrder,p.id") List<PortfolioProjectTranslation> findPublishedByLanguage(@Param("language") LanguageCode language); }
